.sidebar {
  width: calc(100% - 300px);
}
.centered {
  margin-left: calc(50% - 200px);
}
.spacing {
  padding: calc(1rem + 2vw);
}
/* ネスト可能 */
.complex {
  width: calc(100% - calc(2 * var(--gap)));
}

/* コンテナ幅の制限 */
.container {
  width: min(1200px, 100% - 2rem);
  margin-inline: auto;
}

/* フルードタイポグラフィ */
h1 { font-size: clamp(1.5rem, 4vw + 1rem, 3.5rem); }
p  { font-size: clamp(0.875rem, 1.5vw, 1.125rem); }

/* フルードスペーシング */
.section { padding: clamp(1rem, 5vw, 4rem); }

/* 最小サイズの保証 */
.sidebar { width: max(250px, 25%); }

/* iPhoneのセーフエリア対応 */
body {
  padding-top: env(safe-area-inset-top);
  padding-bottom: env(safe-area-inset-bottom);
  padding-left: env(safe-area-inset-left);
  padding-right: env(safe-area-inset-right);
}

/* フォールバック付き */
.bottom-bar {
  padding-bottom: max(16px, env(safe-area-inset-bottom));
}

/* viewport-fit=cover が前提 */
<meta name="viewport"
      content="width=device-width, initial-scale=1, viewport-fit=cover">

/* 50px刻みにスナップ */
.grid-snap {
  width: round(nearest, 100%, 50px);
}

/* 上方向に丸め */
.round-up {
  height: round(up, 100vh, 8px);
}

/* 下方向に丸め */
.round-down {
  font-size: round(down, 2.5rem, 0.25rem);
}

/* 剰余 */
.pattern {
  /* mod()とrem()は負数での挙動が異なる */
  margin: mod(100px, 30px); /* = 10px */
}

/* 絶対値 */
.box {
  --offset: -20px;
  margin-left: abs(var(--offset)); /* = 20px */
}

/* 符号（-1, 0, 1） */
.arrow {
  --direction: -1; /* 左向き */
  transform: scaleX(sign(var(--direction)));
}

/* 距離の計算 */
.distance {
  width: calc(abs(var(--end) - var(--start)) * 1px);
}

:root {
  --primary: #3b82f6;
}

.btn:hover {
  background: color-mix(in oklch, var(--primary) 80%, black);
}

/* ライトバリエーション */
.bg-light {
  background: color-mix(in oklch, var(--primary) 20%, white);
}

/* 2色の中間色 */
.blend {
  color: color-mix(in srgb, #3b82f6 50%, #ec4899);
}

:root {
  color-scheme: light dark;
}

body {
  background: light-dark(#ffffff, #0f172a);
  color: light-dark(#1e293b, #e2e8f0);
}

.card {
  border: 1px solid light-dark(#e2e8f0, #334155);
  box-shadow: 0 2px 8px light-dark(
    rgba(0,0,0,0.1),
    rgba(0,0,0,0.5)
  );
}

/* 解像度に応じた画像切替 */
.hero {
  background-image: image-set(
    "hero-1x.jpg" 1x,
    "hero-2x.jpg" 2x
  );
}

/* フォーマット切替 */
.card {
  background-image: image-set(
    "bg.avif" type("image/avif"),
    "bg.webp" type("image/webp"),
    "bg.jpg" type("image/jpeg")
  );
}

/* 自動番号付け */
.article {
  counter-reset: section;
}
.article h2 {
  counter-increment: section;
}
.article h2::before {
  content: counter(section) '. ';
  color: #3b82f6;
}

/* ネストされたカウンター */
ol {
  counter-reset: item;
  list-style: none;
}
li::before {
  counter-increment: item;
  content: counters(item, '.') ' ';
  font-weight: bold;
}
/* 出力: 1, 1.1, 1.2, 2, 2.1... */

/* fit-content: コンテンツに合わせて最大値を制限 */
.grid {
  grid-template-columns: fit-content(200px) 1fr;
}

/* minmax: 最小〜最大の範囲 */
.card-grid {
  grid-template-columns: repeat(
    auto-fill, minmax(250px, 1fr)
  );
}

/* 組み合わせ */
.layout {
  grid-template-columns:
    minmax(200px, 300px)  /* サイドバー */
    minmax(0, 1fr);       /* メイン */
}
